{
  "last_updated": "2026-03-28T10:30:00+08:00",
  "category": "skill-memory",
  "content": {
    "title": "行程管理避坑指南 - Notion 資料庫操作規範",
    "description": "記錄新增與查詢行程過程中的注意事項與錯誤案例",
    "last_reviewed": "2026-03-28T10:30:00+08:00"
  },
  "memories": [
    {
      "id": "pm-001",
      "category": "日期時間處理",
      "rule": "Notion 日期欄位雖標示為 date，但可存 datetime（含時分）；務必保留時區資訊（如 UTC+08），避免跨時區混淆；時間精確到分鐘，不要只寫日期。",
      "example": "錯誤：2026-03-28\n正確：2026-03-28T07:30:00+08:00"
    },
    {
      "id": "pm-002",
      "category": "資料庫 ID vs 數據源 ID",
      "rule": "database_id 用於查詢/新增頁面；data_source_id 是父層引用，兩者不可混用；避免將 database_id 當作 data_source_id 傳遞給工具。",
      "example": "資料庫 ID: 3305aafd-db3b-812a-bec0-de994cfbd764\n數據源 ID: f199688f-e08a-48b5-a0db-f1e4b683dae4"
    },
    {
      "id": "pm-003",
      "category": "頁面 ID 追蹤",
      "rule": "每次修改前記錄頁面 ID（如 3305aafd...）；刪除前先確認 ID 正確，避免誤刪其他行程；建議先查詢再操作，不要直接猜測 ID。",
      "example": "去台北看房 -> 3305aafd-db3b-8110-a07a-d91e9ff1852b\n實驗室行程 -> 3305aafd-db3b-81a9-b2d8-d53cd5ab96d2"
    },
    {
      "id": "pm-004",
      "category": "工具步驟限制",
      "rule": "delegated skill 有最大步驟上限；複雜任務需拆解成單一技能步驟執行；避免一次請求包含多個獨立操作。",
      "example": "新增行程時先查詢現有數據，再決定是否重複或修改"
    },
    {
      "id": "pm-005",
      "category": "狀態欄位處理",
      "rule": "狀態字段可能為 select 類型，值影響查詢結果；新增行程時建議預設狀態（如「未完成」）；刪除前檢查狀態是否需先更動。",
      "example": "狀態選單：已完成 / 進行中 / 未完成"
    },
    {
      "id": "pm-006",
      "category": "標籤一致性",
      "rule": "多選標籤命名要規範（如統一用繁體中文）；避免混用簡體或英文，造成查詢錯誤；新增時可預設空標籤或由系統自動標記。",
      "example": "正確：其他 / 工作 / 私人\n錯誤：Other / work / personal"
    },
    {
      "id": "pm-007",
      "category": "備註欄位格式",
      "rule": "rich_text 支援內嵌連結與格式；避免過長內容導致截斷；重要資訊建議加粗或標示關鍵字。",
      "example": "地點：實驗室，預計停留 2 小時"
    },
    {
      "id": "pm-008",
      "category": "查詢過濾條件",
      "rule": "過濾條件要精確（如「日期=今天」而非模糊文字）；避免使用過多 OR/AND 邏輯造成性能下降；測試時先用空過濾確認總筆數。",
      "example": "錯誤：包含所有日期的行程\n正確：filter.date.start = 2026-03-28T07:30:00+08:00"
    },
    {
      "id": "pm-009",
      "category": "備份機制",
      "rule": "修改前可先讀取原始內容作為參考；刪除操作不可逆，建議先移至回收站；重要變更記錄在日誌或備註欄位。",
      "example": "刪除實驗室行程前先查詢確認 ID 正確"
    },
    {
      "id": "pm-010",
